  { id: '#ORD-1046', name: '박서연', product: '한우 불고기 500g', pay: '무통장', amount: 52000, status: '입금대기', date: '2026.05.07 12:55', phone: '010-3456-7890', addr: '경기 고양시 일산동 77' },
