  { id: '#ORD-1043', name: '강민서', product: '국산 콩나물 500g', pay: '신용카드', amount: 3200, status: '배송완료', date: '2026.05.06 18:05', phone: '010-6789-0123', addr: '경기 수원시 권선구 88' },
  { id: '#ORD-1042', name: '윤지호', product: '제철 참외 2kg', pay: '카카오페이', amount: 12400, status: '배송완료', date: '2026.05.06 15:30', phone: '010-7890-1234', addr: '대전 유성구 봉명동 99' },
