];

const STATUS_STYLE = {
  결제완료: { bg: sgl, color: sgd },
  배송중: { bg: '#e6f1fb', color: '#185fa5' },
  배송완료: { bg: '#eaf3de', color: '#3b6d11' },
  입금대기: { bg: '#faeeda', color: '#854f0b' },
  취소: { bg: '#fcebeb', color: '#a32d2d' },
};
const TABS = ['전체', '결제완료', '배송중', '배송완료', '입금대기', '취소'];

export default function OrderManagement({ setPage }) {
  const [activeTab, setActiveTab] = useState('전체');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [payFilter, setPayFilter] = useState('');
  const [selectedOrder, setSelectedOrder] = useState(null);

  const filtered = ORDERS.filter(o => {
    if (activeTab !== '전체' && o.status !== activeTab) return false;
    if (statusFilter && o.status !== statusFilter) return false;
    if (payFilter && o.pay !== payFilter) return false;
    if (search && !o.id.includes(search) && !o.name.includes(search)) return false;
    return true;
  });

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f5f5f3', fontFamily: 'sans-serif' }}>
      <Sidebar currentPage="adminPC_orders" setPage={setPage} />
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={s.topbar}>
          <div style={s.topbarTitle}>주문 관리</div>
        </div>
        <div style={s.content}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5,1fr)', gap: 10, marginBottom: 16 }}>
            {[{ label: '전체 주문', value: '1,284', color: '#333' }, { label: '결제완료', value: '847', color: sgd }, { label: '배송 중', value: '23', color: '#185fa5' }, { label: '입금대기', value: '7', color: '#854f0b' }, { label: '취소/환불', value: '34', color: '#a32d2d' }].map(c => (
              <div key={c.label} style={s.sumCard}><div style={s.sumLabel}>{c.label}</div><div style={{ fontSize: 17, fontWeight: 500, color: c.color }}>{c.value}</div></div>
            ))}
          </div>
          <div style={{ display: 'flex', borderBottom: '0.5px solid #eee', marginBottom: 14 }}>
            {TABS.map(t => (
              <div key={t} onClick={() => setActiveTab(t)} style={{ padding: '8px 16px', fontSize: 12, cursor: 'pointer', color: activeTab === t ? sg : '#888', borderBottom: activeTab === t ? `2px solid ${sg}` : '2px solid transparent', fontWeight: activeTab === t ? 500 : 400, marginBottom: -0.5 }}>{t}</div>
            ))}
          </div>
          <div style={{ display: 'flex', gap: 10, marginBottom: 14 }}>
            <input style={{ ...s.input, flex: 1 }} placeholder="주문번호, 고객명 검색..." value={search} onChange={e => setSearch(e.target.value)} />
            <select style={s.select} value={statusFilter} onChange={e => setStatusFilter(e.target.value)}>
              <option value="">전체 상태</option>
              {['결제완료','배송중','배송완료','입금대기','취소'].map(v => <option key={v}>{v}</option>)}
            </select>
            <select style={s.select} value={payFilter} onChange={e => setPayFilter(e.target.value)}>
              <option value="">전체 결제</option>
              {['카카오페이','신용카드','무통장'].map(v => <option key={v}>{v}</option>)}
            </select>
          </div>
          <div style={s.tableCard}>
            <table style={s.table}>
              <thead style={{ background: '#f5f5f3' }}>
                <tr>{['주문번호','고객명','상품','결제수단','금액','상태','주문일시','관리'].map(h => <th key={h} style={s.th}>{h}</th>)}</tr>
              </thead>
              <tbody>
                {filtered.map(o => (
                  <tr key={o.id}>
                    <td style={{ ...s.td, fontWeight: 500 }}>{o.id}</td>
                    <td style={{ ...s.td, color: '#666' }}>{o.name}</td>
                    <td style={{ ...s.td, maxWidth: 140, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{o.product}</td>
                    <td style={{ ...s.td, color: '#666' }}>{o.pay}</td>
                    <td style={{ ...s.td, fontWeight: 500 }}>₩{o.amount.toLocaleString()}</td>
                    <td style={s.td}><span style={{ ...s.pill, background: STATUS_STYLE[o.status]?.bg, color: STATUS_STYLE[o.status]?.color }}>{o.status}</span></td>
                    <td style={{ ...s.td, color: '#aaa', fontSize: 11 }}>{o.date}</td>
                    <td style={s.td}><button style={s.actionBtn} onClick={() => setSelectedOrder(o)}>상세</button></td>
                  </tr>
                ))}
                {filtered.length === 0 && <tr><td colSpan={8} style={{ padding: 32, textAlign: 'center', color: '#aaa', fontSize: 13 }}>검색 결과가 없어요</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      {selectedOrder && (
        <div style={s.modalBg} onClick={() => setSelectedOrder(null)}>
          <div style={s.modal} onClick={e => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 18 }}>
              <span style={{ fontSize: 15, fontWeight: 500 }}>주문 상세 — {selectedOrder.id}</span>
              <button style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 18, color: '#888' }} onClick={() => setSelectedOrder(null)}>✕</button>
            </div>
            {[['주문번호', selectedOrder.id], ['고객명', selectedOrder.name], ['연락처', selectedOrder.phone], ['배송지', selectedOrder.addr], ['상품', selectedOrder.product], ['결제수단', selectedOrder.pay], ['결제금액', `₩${selectedOrder.amount.toLocaleString()}`], ['주문일시', selectedOrder.date]].map(([l, v]) => (
              <div key={l} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, padding: '7px 0', borderBottom: '0.5px solid #eee' }}>
                <span style={{ color: '#888' }}>{l}</span><span style={{ fontWeight: 500 }}>{v}</span>
              </div>
            ))}
            <div style={{ marginTop: 18, display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
              <button style={s.btn} onClick={() => setSelectedOrder(null)}>닫기</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const s = {
  topbar: { background: '#fff', borderBottom: '0.5px solid #eee', padding: '0 24px', height: 52, display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0 },
  topbarTitle: { fontSize: 15, fontWeight: 500 },
  content: { flex: 1, overflowY: 'auto', padding: '20px 24px' },
  sumCard: { background: '#f5f5f3', borderRadius: 8, padding: '10px 14px', textAlign: 'center' },
