  td: { padding: '10px 14px', borderBottom: '0.5px solid #eee', verticalAlign: 'middle' },
  pill: { display: 'inline-block', fontSize: 10, padding: '2px 9px', borderRadius: 10, fontWeight: 500 },
  actionBtn: { background: 'none', border: '0.5px solid #ddd', borderRadius: 8, padding: '4px 10px', fontSize: 11, color: '#888', cursor: 'pointer' },
  btn: { padding: '6px 14px', borderRadius: 8, border: '0.5px solid #ddd', background: '#fff', fontSize: 12, cursor: 'pointer' },
  modalBg: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', zIndex: 100, display: 'flex', alignItems: 'center', justifyContent: 'center' },
  modal: { background: '#fff', borderRadius: 12, padding: 24, width: 460, border: '0.5px solid #eee' },
};
